import HelpTooltip from './ui/HelpTooltip';
import { useAuth } from '../contexts/AuthContext';

interface HeaderProps {
  saveStatus?: 'saved' | 'unsaved' | 'saving' | 'error';
  currentMonthYear: string;
  onPreviousMonth: () => void;
  onNextMonth: () => void;
  onEdit: () => void;
  onShare: () => void;
  onImportExport: () => void;
  onRecommendations: () => void;
  view: View;
  setView: (view: View) => void;
  onLogout: () => Promise<void>;
  onSave?: () => Promise<void>;
}

const Header: React.FC<HeaderProps> = ({ 
  saveStatus,
  currentMonthYear, 
  onPreviousMonth, 
  onNextMonth,
  onEdit,
  onShare,
  onImportExport,
  onRecommendations,
  view,
  setView,
  onLogout,
  onSave
}) => {
  const { user } = useAuth();
  const isGuest = user && 'isGuest' in user;

  const SaveStatusButton = () => {
      if (isGuest || !onSave) return null;

      if (saveStatus === 'saving') {
          return <Button variant="secondary" size="small" disabled>Saving...</Button>;
      }
      if (saveStatus === 'saved') {
          return <Button variant="secondary" size="small" disabled className="!bg-green-100 dark:!bg-green-800/50 !text-positive"><CheckIcon /> Saved</Button>;
      }
      if (saveStatus === 'error') {
          return <Button onClick={onSave} variant="danger" size="small"><AlertTriangleIcon /> Save Error</Button>;
      }
      // unsaved
      return <Button onClick={onSave} variant="primary" size="small"><SaveIcon /> Save</Button>;
  };


  return (
    <header className="bg-white dark:bg-gray-800 shadow-md p-4 mb-6 rounded-lg">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 items-center">

        <div className="flex flex-col items-center lg:items-start">
          <div className="flex items-center gap-2 justify-center lg:justify-start">
            <h1 className="text-2xl font-bold text-brand-primary dark:text-brand-light whitespace-nowrap">What's My Credit Worth?</h1>
            <HelpTooltip 
              text="Welcome to your personal finance dashboard! Use this app to track your financial health. Click 'Edit Data' to enter your monthly income, assets, and liabilities. Use the arrows to navigate your history, 'Import/Export' to save or load data, and 'Share' to create a read-only snapshot. The 'Reports' tab compares your progress over time."
            />
          </div>
          <button 
            onClick={onRecommendations} 
            className="mt-1 flex items-center gap-1.5 px-3 py-1 rounded-full bg-purple-50 hover:bg-purple-100 text-purple-700 text-xs font-bold transition-colors border border-purple-200"
          >
            <SparklesIcon />
            <span>RECOMMENDATIONS</span>
          </button>
        </div>

        <div className="flex items-center justify-center gap-4">
            <div className="flex items-center gap-4">
                <button onClick={onPreviousMonth} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"><ChevronLeftIcon /></button>
                <span className="font-semibold text-lg w-32 text-center">{formatMonthYear(currentMonthYear)}</span>
                <button onClick={onNextMonth} className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"><ChevronRightIcon /></button>
            </div>

            <div className="flex items-center bg-gray-100 dark:bg-gray-700 p-1 rounded-lg">
            {(['dashboard', 'reports'] as View[]).map(v => (
                <button
                key={v}
                onClick={() => setView(v)}
                className={`px-4 py-2 text-sm font-medium rounded-md transition-colors capitalize ${
                    view === v
                    ? 'bg-brand-primary text-white'
                    : 'text-gray-600 dark:text-gray-300 hover:bg-brand-light hover:text-brand-primary'
                }`}
                >
                {v}
                </button>
            ))}
            </div>
        </div>

        <div className="flex items-center gap-4 flex-wrap justify-center lg:justify-end">
            {user && (
                <div className="flex items-center gap-2 border-r pr-4 mr-2">
                    <span className="text-sm font-medium text-gray-700 dark:text-gray-300 truncate" title={user.displayName || 'User'}>
                        {user.displayName}
                    </span>
                    <Button onClick={onLogout} variant="secondary" size="small">Logout</Button>
                </div>
            )}
            <SaveStatusButton />
            <Button onClick={onEdit} variant="primary"><EditIcon /> Edit Data</Button>
            <Button onClick={onImportExport} variant="secondary"><ImportIcon /> Import/Export</Button>
            <Button onClick={onShare} variant="secondary"><ShareIcon /> Share</Button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { MonthlyData } from '../types';
import { calculateNetWorth, calculateMonthlyIncome, formatCurrency, calculateTotalBalance } from '../utils/helpers';
import Button from './ui/Button';
import { SparklesIcon, InfoIcon } from './ui/Icons';
import Card from './ui/Card';

interface RecommendationsModalProps {
  isOpen: boolean;
  onClose: () => void;
  data: MonthlyData;
  monthYear: string;
}

interface Recommendation {
  title: string;
  description: string;
  category: string;
  actionItem: string;
}

const RecommendationsModal: React.FC<RecommendationsModalProps> = ({ isOpen, onClose, data, monthYear }) => {
  const [loading, setLoading] = useState(false);
  const [recommendations, setRecommendations] = useState<Recommendation[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (isOpen && !recommendations) {
      fetchRecommendations();
    }
  }, [isOpen]);

  const fetchRecommendations = async () => {
    setLoading(true);
    setError(null);

    try {
      // 1. Prepare data for the prompt
      const netWorth = calculateNetWorth(data);
      const income = calculateMonthlyIncome(data.income.jobs);
      const totalDebt = calculateTotalBalance(data.creditCards) + calculateTotalBalance(data.loans);

      const scores = Object.entries(data.creditScores)
         .map(([key, val]) => {
             const score = typeof val === 'object' && val !== null && 'score8' in val ? val.score8 : val;
             return `${key}: ${score}`;
         })
         .join(', ');

      const financialProfile = `
        Month: ${monthYear}
        Net Worth: ${formatCurrency(netWorth)}
        Monthly Income: ${formatCurrency(income)}
        Total Debt: ${formatCurrency(totalDebt)}
        Credit Scores: ${scores}
        Assets: ${data.assets.map(a => `${a.name} ($${a.value})`).join(', ')}
        Liabilities: ${[...data.creditCards, ...data.loans].map(l => `${l.name} ($${l.balance})`).join(', ')}
      `;

      // 2. Initialize GenAI
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // 3. Define Schema
      const schema = {
        type: Type.OBJECT,
        properties: {
            recommendations: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        category: { type: Type.STRING, description: "One of: 'Credit Cards', 'Loans', 'Savings', 'Investments', 'General'" },
                        actionItem: { type: Type.STRING, description: "A specific, short actionable step." }
                    }
                }
            }
        }
      };

      // 4. Call Model
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: `Act as a financial expert. Analyze the following financial profile and provide 4-5 tailored recommendations.

        Focus on:
        1. Loans or Credit Cards that match this profile (e.g., balance transfer, rewards, debt consolidation, credit building).
        2. Savings Account and Investment strategies to increase net worth (e.g., HYSA, index funds, debt payoff avalanche/snowball).

        Profile:
        ${financialProfile}

        Return the result as JSON.`,
        config: {
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.7
        }
      });

      const responseText = response.text;
      if (responseText) {
          const parsed = JSON.parse(responseText);
          setRecommendations(parsed.recommendations);
      } else {
          setError("No recommendations generated.");
      }

    } catch (err: any) {
      console.error("Error generating recommendations:", err);
      setError("Failed to generate recommendations. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4">
      <div className="bg-white dark:bg-gray-900 rounded-lg shadow-xl w-full max-w-4xl max-h-[90vh] flex flex-col">
        <div className="p-6 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between bg-purple-50 dark:bg-gray-800 rounded-t-lg">
           <div className="flex items-center gap-3">
              <div className="p-2 bg-purple-100 rounded-full text-purple-600">
                <SparklesIcon />
              </div>
              <div>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-100">AI Financial Recommendations</h2>
                <p className="text-sm text-gray-600 dark:text-gray-400">Tailored advice based on your {monthYear} snapshot</p>
              </div>
           </div>
           <button onClick={onClose} className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200">
             <span className="text-2xl">&times;</span>
           </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-gray-50 dark:bg-gray-900/50">
           {loading ? (
             <div className="flex flex-col items-center justify-center h-64 space-y-4">
               <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-purple-600"></div>
               <p className="text-purple-600 font-medium animate-pulse">Analyzing your finances...</p>
             </div>
           ) : error ? (
             <div className="text-center py-10">
               <div className="text-red-500 mb-2">
                 <InfoIcon />
               </div>
               <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100">Oops!</h3>
               <p className="text-gray-600 dark:text-gray-400 mb-4">{error}</p>
               <Button onClick={fetchRecommendations}>Try Again</Button>
             </div>
           ) : (
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {recommendations?.map((rec, index) => (
                    <Card key={index} title={
                        <div className="flex items-center justify-between">
                            <span>{rec.title}</span>
                            <span className="text-xs font-bold uppercase tracking-wide bg-gray-100 dark:bg-gray-700 px-2 py-1 rounded text-gray-600 dark:text-gray-300">
                                {rec.category}
                            </span>
                        </div>
                    } className="transform transition-all hover:scale-[1.01] hover:shadow-lg border border-purple-100 dark:border-gray-700">
                        <div className="space-y-4">
                            <p className="text-gray-600 dark:text-gray-300 text-sm leading-relaxed">
                                {rec.description}
                            </p>
                            <div className="bg-purple-50 dark:bg-purple-900/20 p-3 rounded-lg border border-purple-100 dark:border-purple-800/30">
