    } else {
      const docRef = doc(db, 'users', user.uid);
      getDoc(docRef).then(docSnap => {
        if (docSnap.exists()) {
          const cloudData = docSnap.data() as FinancialData;
          setFinancialData(cloudData);
          dataRef.current = cloudData;
          setSaveStatus('saved');
        } else {
          const storedData = localStorage.getItem(LOCAL_STORAGE_KEY);
          let dataToMigrate: FinancialData = {};
          if (storedData) {
            try {
              dataToMigrate = JSON.parse(storedData);
              localStorage.removeItem(LOCAL_STORAGE_KEY);
            } catch (error) {
              console.error("Error parsing local data for migration", error);
            }
          }
          setFinancialData(dataToMigrate);
          dataRef.current = dataToMigrate;
          setDoc(docRef, dataToMigrate)
            .then(() => setSaveStatus('saved'))
            .catch(err => {
              console.error("Error creating initial user doc", err);
              setSaveStatus('error');
            });
        }
      }).catch(error => {
        console.error("Error fetching from Firestore:", error);
        setSaveStatus('error');
      });
    }
  }, [user?.uid]); // Only re-run if UID changes

  // Robust save function - returns a Promise
  const saveData = useCallback(async (): Promise<void> => {
    if (!user || isSavingRef.current) return;

    isSavingRef.current = true;
    setSaveStatus('saving');

    const currentData = dataRef.current;

    // Ensure keys are sorted for consistent storage
    const sortedData = Object.keys(currentData).sort().reduce((obj, key) => {
        obj[key] = currentData[key];
        return obj;
    }, {} as FinancialData);

    try {
      if ('isGuest' in user && user.isGuest) {
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(sortedData));
      } else {
        const docRef = doc(db, 'users', user.uid);
        await setDoc(docRef, sortedData);
      }
      setSaveStatus('saved');
      setRefreshCounter(prev => prev + 1); // Trigger a refresh key
    } catch (error) {
      console.error("Error persisting data:", error);
      setSaveStatus('error');
      throw error;
    } finally {
      isSavingRef.current = false;
    }
  }, [user]);

  // Debounced Autosave Effect
  useEffect(() => {
    if (saveStatus === 'unsaved') {
      const timer = setTimeout(() => {
        saveData();
      }, 3000); // 3 second debounce for autosave
      return () => clearTimeout(timer);
    }
  }, [financialData, saveStatus, saveData]);

  const updateMonthData = useCallback((monthYear: string, data: MonthlyData) => {
    setFinancialData(prev => {
      const next = { ...prev, [monthYear]: data };
      dataRef.current = next; // CRITICAL: Update ref immediately
      return next;
    });
    setSaveStatus('unsaved');
  }, []);

  const getMonthData = useCallback((monthYear: string): MonthlyData => {
      return financialData[monthYear] || getInitialData();
  }, [financialData]);

  const importData = useCallback((jsonString: string) => {
    try {
      const parsedData = JSON.parse(jsonString);
      if (typeof parsedData === 'object' && parsedData !== null) {
        setFinancialData(parsedData as FinancialData);
        dataRef.current = parsedData; // Update ref immediately
        setSaveStatus('unsaved');
        alert('Data imported! The app will save your changes automatically.');
      } else {
        throw new Error("Invalid format");
      }
    } catch (error) {
      console.error("Import failed", error);
      throw error;
    }
  }, []);

  const exportData = useCallback(() => {
    const jsonString = JSON.stringify(financialData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-data-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, [financialData]);

  const exportTemplateData = useCallback(() => {
    const templateData: FinancialData = { [getCurrentMonthYear()]: getInitialData() };
    const jsonString = JSON.stringify(templateData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-template.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, []);

  const hasData = useCallback(() => Object.keys(financialData).length > 0, [financialData]);

  return { 
    financialData, 
    updateMonthData, 
    getMonthData, 
    importData, 
    exportData, 
    hasData, 
    exportTemplateData, 
    saveData, 
    saveStatus,
    refreshCounter
  };
}

import React, { useState, useEffect } from 'react';
import type { MonthlyData, NamedAmount, CreditCard, Loan, Asset, IncomeSource } from '../types';
import { useFinancialData } from '../hooks/useFinancialData';
import { formatMonthYear } from '../utils/helpers';
import Button from './ui/Button';
import { AddIcon, DeleteIcon, SaveIcon } from './ui/Icons';

interface DataEditorProps {
  isOpen: boolean;
  onClose: () => void;
  monthYear: string;
}

const InputField = React.forwardRef<HTMLInputElement, React.InputHTMLAttributes<HTMLInputElement> & { label: string }>(({ label, ...props }, ref) => (
    <div>
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">{label}</label>
        <input ref={ref} {...props} className="mt-1 block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-brand-secondary focus:border-brand-secondary sm:text-sm" />
    </div>
));

type ItemType = 'creditCards' | 'loans' | 'assets' | 'monthlyBills';

const DataEditor: React.FC<DataEditorProps> = ({ isOpen, onClose, monthYear }) => {
  const { getMonthData, updateMonthData, financialData, saveData } = useFinancialData();
  const [data, setData] = useState<MonthlyData>(getMonthData(monthYear));
  const [copyFromMonth, setCopyFromMonth] = useState<string>('');
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    if (isOpen) {
      setData(getMonthData(monthYear));
      setCopyFromMonth(''); 
      setIsSaving(false);
    }
  }, [monthYear, getMonthData, isOpen]);

  if (!isOpen) return null;

  const availableMonths = Object.keys(financialData)
    .filter(m => m !== monthYear)
    .sort((a, b) => b.localeCompare(a));

  const handleCopyData = () => {
    if (!copyFromMonth) return;

    if (window.confirm(`Are you sure you want to replace this month's data with the data from ${formatMonthYear(copyFromMonth)}? All current edits will be lost.`)) {
        const dataToCopy = getMonthData(copyFromMonth);
        const deepClonedData = JSON.parse(JSON.stringify(dataToCopy));

        deepClonedData.income.jobs.forEach((item: IncomeSource) => item.id = crypto.randomUUID());
        deepClonedData.creditCards.forEach((item: CreditCard) => item.id = crypto.randomUUID());
        deepClonedData.loans.forEach((item: Loan) => item.id = crypto.randomUUID());
        deepClonedData.assets.forEach((item: Asset) => item.id = crypto.randomUUID());
        deepClonedData.monthlyBills.forEach((item: NamedAmount) => item.id = crypto.randomUUID());

        setData(deepClonedData);
        setCopyFromMonth(''); 
    }
  };

  const handleSimpleChange = (e: React.ChangeEvent<HTMLInputElement>, ...path: string[]) => {
    const { name, value } = e.target;
    const numValue = Number(value) || 0;

    setData(prev => {
        if (path.length === 1) {
            const section = path[0] as keyof MonthlyData;
            return {
                ...prev,
                [section]: {
                    ...(prev[section] as any),
                    [name]: numValue
                }
            };
        }
        if (path.length === 2) {
            const section = path[0] as keyof MonthlyData;
            const subsection = path[1];
            const currentSection = prev[section] as any;
            return {
                ...prev,
                [section]: {
                    ...currentSection,
                    [subsection]: {
                        ...currentSection[subsection],
                        [name]: numValue
                    }
                }
            };
        }
        return prev;
    });
  };

  const handleJobsChange = (index: number, e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setData(prev => {
        const jobs = [...prev.income.jobs];
        jobs[index] = { 
            ...jobs[index], 
            [name]: name === 'name' || name === 'frequency' ? value : Number(value) || 0 
        };
        return { 
            ...prev, 
            income: { ...prev.income, jobs } 
        };
    });
  };

  const handleAddJob = () => {
      setData(prev => {
          const newJob: IncomeSource = { id: crypto.randomUUID(), name: 'New Job', amount: 0, frequency: 'bi-weekly' };
          return {...prev, income: {...prev.income, jobs: [...prev.income.jobs, newJob]}}
      })
  };

  const handleRemoveJob = (index: number) => {
      setData(prev => {
          const jobs = prev.income.jobs.filter((_, i) => i !== index);
          return {...prev, income: {...prev.income, jobs}};
      })
  }

  const handleListChange = (index: number, e: React.ChangeEvent<HTMLInputElement>, list: ItemType) => {
    const { name, value } = e.target;
    setData(prev => {
        const items = [...prev[list]];
        items[index] = { 
            ...items[index], 
            [name]: name === 'name' ? value : Number(value) || 0 
        };
        return { ...prev, [list]: items as any };
    });
  };

  const handleAddItem = <T,>(list: ItemType, newItem: T) => {
    setData(prev => ({...prev, [list]: [...prev[list], newItem] as any}));
  };

  const handleRemoveItem = (index: number, list: ItemType) => {
    setData(prev => ({ ...prev, [list]: prev[list].filter((_, i) => i !== index) as any }));
  };

  const handleSave = async () => {
    if (isSaving) return;
    setIsSaving(true);
    try {
        updateMonthData(monthYear, data);
        // Force an immediate save to ensure "persistence" and "refresh"
        await saveData();
        onClose();
    } catch (err) {
        console.error("Save error:", err);
        alert("Failed to save changes. Please try again.");
    } finally {
        setIsSaving(false);
    }
  };

  const renderListEditor = <T extends {id: string, name: string}>(
    title: string, 
    listName: ItemType, 
    items: T[], 
    fields: (keyof T)[]
  ) => (
    <div className="space-y-4">
        <h3 className="text-lg font-semibold border-b pb-2">{title}</h3>
        {items.map((item, index) => (
            <div key={item.id} className="grid grid-cols-1 md:grid-cols-4 gap-2 items-end p-2 rounded-md bg-gray-50 dark:bg-gray-800">
                {fields.map(field => (
                    <InputField 
                        key={String(field)}
                        label={String(field).charAt(0).toUpperCase() + String(field).slice(1)}
                        name={String(field)}
                        type={field === 'name' ? 'text' : 'number'}
                        value={item[field] as any}
                        onChange={(e) => handleListChange(index, e, listName)}
                    />
                ))}
                 <Button onClick={() => handleRemoveItem(index, listName)} variant="danger" size="small"><DeleteIcon /></Button>
            </div>
        ))}
         <Button onClick={() => {
             const newItem: any = { id: crypto.randomUUID(), name: 'New Item' };
             fields.filter(f => f !== 'id' && f !== 'name').forEach(f => newItem[f] = 0);
             handleAddItem<any>(listName, newItem);
         }} size="small"><AddIcon /> Add {title.slice(0, -1)}</Button>
    </div>
  );


  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center">
      <div className="bg-white dark:bg-gray-900 rounded-lg shadow-xl w-full max-w-4xl max-h-[90vh] overflow-y-auto">
        <div className="p-6 sticky top-0 bg-white dark:bg-gray-900 border-b z-10">
            <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Edit Data for {formatMonthYear(monthYear)}</h2>
            {availableMonths.length > 0 && (
              <div className="mt-4 flex flex-col sm:flex-row items-stretch sm:items-center gap-2 p-3 bg-gray-50 dark:bg-gray-800/50 rounded-lg">
                <label htmlFor="copy-month-select" className="text-sm font-medium text-gray-700 dark:text-gray-300 whitespace-nowrap">
                  Start with data from another month?
                </label>
                <div className="flex-grow flex items-center gap-2">
                    <select
                        id="copy-month-select"
                        value={copyFromMonth}
                        onChange={(e) => setCopyFromMonth(e.target.value)}
                        className="block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-brand-secondary focus:border-brand-secondary sm:text-sm"
                    >
                        <option value="">Select a month...</option>
                        {availableMonths.map(m => (
                            <option key={m} value={m}>{formatMonthYear(m)}</option>
                        ))}
                    </select>
                    <Button onClick={handleCopyData} disabled={!copyFromMonth} size="small">
                        Copy Data
                    </Button>
                </div>
              </div>
            )}
        </div>
        <div className="p-6 space-y-6">
            <div className="space-y-4">
                <h3 className="text-lg font-semibold border-b pb-2">Credit Scores</h3>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <InputField label="Experian FICO 8" name="score8" type="number" value={data.creditScores.experian.score8} onChange={e => handleSimpleChange(e, 'creditScores', 'experian')} />
                    <InputField label="Equifax FICO 8" name="score8" type="number" value={data.creditScores.equifax.score8} onChange={e => handleSimpleChange(e, 'creditScores', 'equifax')} />
                    <InputField label="TransUnion FICO 8" name="score8" type="number" value={data.creditScores.transunion.score8} onChange={e => handleSimpleChange(e, 'creditScores', 'transunion')} />
                    <InputField label="Lending Tree" name="lendingTree" type="number" value={data.creditScores.lendingTree} onChange={e => handleSimpleChange(e, 'creditScores')} />
                    <InputField label="Credit Karma" name="creditKarma" type="number" value={data.creditScores.creditKarma} onChange={e => handleSimpleChange(e, 'creditScores')} />
                    <InputField label="Credit Sesame" name="creditSesame" type="number" value={data.creditScores.creditSesame} onChange={e => handleSimpleChange(e, 'creditScores')} />
                    <InputField label="Mr. Cooper FICO 4" name="mrCooper" type="number" value={data.creditScores.mrCooper} onChange={e => handleSimpleChange(e, 'creditScores')} />
                </div>
            </div>

            <div className="space-y-4">
                <h3 className="text-lg font-semibold border-b pb-2">Income</h3>
                {data.income.jobs.map((job, index) => (
                    <div key={job.id} className="grid grid-cols-1 md:grid-cols-4 gap-2 items-end p-2 rounded-md bg-gray-50 dark:bg-gray-800">
                        <InputField 
                            label="Source"
                            name="name"
                            type="text"
                            value={job.name}
                            onChange={(e) => handleJobsChange(index, e)}
                        />
                        <InputField 
                            label="Amount"
                            name="amount"
                            type="number"
                            value={job.amount}
                            onChange={(e) => handleJobsChange(index, e)}
                        />
                        <div>
                            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Frequency</label>
                            <select 
                                name="frequency"
                                value={job.frequency}
                                onChange={(e) => handleJobsChange(index, e)}
                                className="mt-1 block w-full px-3 py-2 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:outline-none focus:ring-brand-secondary focus:border-brand-secondary sm:text-sm"
                            >
                                <option value="weekly">Weekly</option>
                                <option value="bi-weekly">Bi-weekly</option>
                                <option value="twice-a-month">Twice a month</option>
                                <option value="monthly">Monthly</option>
                                <option value="yearly">Yearly</option>
                            </select>
                        </div>
                         <Button onClick={() => handleRemoveJob(index)} variant="danger" size="small"><DeleteIcon /></Button>
                    </div>
                ))}
                 <Button onClick={handleAddJob} size="small"><AddIcon /> Add Income Source</Button>
            </div>

            {renderListEditor<CreditCard>('Credit Cards', 'creditCards', data.creditCards, ['name', 'balance', 'limit'])}
            {renderListEditor<Loan>('Mortgages and Loans', 'loans', data.loans, ['name', 'balance', 'limit'])}
            {renderListEditor<Asset>('Assets', 'assets', data.assets, ['name', 'value'])}
            {renderListEditor<NamedAmount>('Monthly Bills', 'monthlyBills', data.monthlyBills, ['name', 'amount'])}
        </div>
        <div className="p-6 flex justify-end gap-4 sticky bottom-0 bg-white dark:bg-gray-900 border-t">
          <Button onClick={onClose} variant="secondary" disabled={isSaving}>Cancel</Button>
          <Button onClick={handleSave} disabled={isSaving}>
            {isSaving ? (
                <>
                    <div className="animate-spin rounded-full h-4 w-4 border-t-2 border-b-2 border-white mr-2"></div>
                    Saving...
                </>
            ) : (
                <>
                    <SaveIcon />
                    Save Changes
                </>
            )}
          </Button>
        </div>
      </div>
    </div>
  );
};

export default DataEditor;

import React, { useState, useMemo, useRef } from 'react';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import DataEditor from './components/DataEditor';
import { useFinancialData } from './hooks/useFinancialData';
import { getCurrentMonthYear, getNextMonthYear, getPreviousMonthYear } from './utils/helpers';
import type { View } from './types';
import Reports from './components/Reports';
import UploadHelpModal from './components/UploadHelpModal';
import ShareModal from './components/ShareModal';
import Snapshot from './components/Snapshot';
import type { MonthlyData } from './types';
import ImportExportModal from './components/ImportExportModal';
import { useAuth } from './contexts/AuthContext';
import AuthScreen from './components/AuthScreen';
import { LoadingScreen } from './components/ui/Spinner';
import RecommendationsModal from './components/RecommendationsModal';

const MainApp: React.FC = () => {
  const { financialData, getMonthData, importData, exportData, hasData, exportTemplateData, saveData, saveStatus, refreshCounter } = useFinancialData();
  const { logout } = useAuth();
  const [currentMonthYear, setCurrentMonthYear] = useState(getCurrentMonthYear());
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isUploadHelpOpen, setIsUploadHelpOpen] = useState(false);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);
  const [isImportExportModalOpen, setIsImportExportModalOpen] = useState(false);
  const [isRecommendationsOpen, setIsRecommendationsOpen] = useState(false);
  const [view, setView] = useState<View>('dashboard');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentMonthData = useMemo(() => getMonthData(currentMonthYear), [getMonthData, currentMonthYear]);

  const handlePreviousMonth = () => setCurrentMonthYear(prev => getPreviousMonthYear(prev));
  const handleNextMonth = () => setCurrentMonthYear(prev => getNextMonthYear(prev));

  const handleFileImport = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const content = e.target?.result as string;
          importData(content);
        } catch (error) {
          console.error(error);
          alert('Failed to import data. Please check the file format.');
        }
      };
      reader.readAsText(file);
    }
    // Reset file input
    if (fileInputRef.current) {
        fileInputRef.current.value = "";
    }
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  const handleLogout = async () => {
    // If there are unsaved changes or a previous save failed, try saving again.
    if (saveStatus === 'unsaved' || saveStatus === 'error') {
      try {
        await saveData();
      } catch (error) {
        // If saving fails, confirm with the user before logging out.
        const confirmLogout = window.confirm("Failed to save your latest changes. Your data may be lost. Are you sure you want to log out?");
        if (!confirmLogout) {
          return; // User cancelled logout
        }
      }
    }
    await logout(); // Proceed with logout if save was successful or user confirmed
  };

  return (
    <div className="bg-gray-100 dark:bg-gray-900 text-gray-900 dark:text-gray-100 min-h-screen font-sans">
      <div className="container mx-auto p-4 md:p-6 lg:p-8">
        <Header 
          currentMonthYear={currentMonthYear}
          onPreviousMonth={handlePreviousMonth}
          onNextMonth={handleNextMonth}
          onEdit={() => setIsEditorOpen(true)}
          onShare={() => setIsShareModalOpen(true)}
          onImportExport={() => setIsImportExportModalOpen(true)}
          onRecommendations={() => setIsRecommendationsOpen(true)}
          view={view}
          setView={setView}
          onLogout={handleLogout}
          onSave={saveData}
          saveStatus={saveStatus}
        />

        <main>
          {view === 'dashboard' && (
            <Dashboard 
              key={`dashboard-${refreshCounter}-${currentMonthYear}`} 
              data={currentMonthData} 
              allData={financialData} 
            />
          )}
          {view === 'reports' && (
            <Reports 
              key={`reports-${refreshCounter}`} 
              allData={financialData} 
            />
          )}
        </main>

        <DataEditor 
          isOpen={isEditorOpen}
          onClose={() => setIsEditorOpen(false)}
          monthYear={currentMonthYear}
        />

        <UploadHelpModal 
          isOpen={isUploadHelpOpen}
          onClose={() => setIsUploadHelpOpen(false)}
          onUploadClick={triggerFileUpload}
          exportTemplateData={exportTemplateData}
        />

        <ShareModal
          isOpen={isShareModalOpen}
          onClose={() => setIsShareModalOpen(false)}
          data={currentMonthData}
          monthYear={currentMonthYear}
        />

        <ImportExportModal
            isOpen={isImportExportModalOpen}
            onClose={() => setIsImportExportModalOpen(false)}
            onUpload={() => {
                setIsImportExportModalOpen(false);
                triggerFileUpload();
            }}
            onDownload={() => {
                setIsImportExportModalOpen(false);
                exportData();
            }}
            onShowHelp={() => {
                setIsImportExportModalOpen(false);
                setIsUploadHelpOpen(true);
            }}
            hasData={hasData()}
        />

        <RecommendationsModal
          isOpen={isRecommendationsOpen}
          onClose={() => setIsRecommendationsOpen(false)}
          data={currentMonthData}
          monthYear={currentMonthYear}
        />

        <input
            type="file"
            accept=".json"
            ref={fileInputRef}
            onChange={handleFileImport}
            style={{ display: 'none' }}
        />
      </div>
    </div>
  );
};


function App() {
  const path = window.location.pathname;

  if (path.startsWith('/snapshot/')) {
    const encodedData = path.substring('/snapshot/'.length);
    const ErrorDisplay = ({ message }: { message: string }) => (
       <div className="h-screen flex items-center justify-center bg-gray-100 dark:bg-gray-900">
          <div className="text-center p-8 bg-white dark:bg-gray-800 rounded-lg shadow-xl max-w-md mx-4">
            <h1 className="text-2xl font-bold text-negative mb-4">Invalid Snapshot Link</h1>
            <p className="text-gray-600 dark:text-gray-300">{message}</p>
             <a href="/" className="mt-6 inline-block bg-brand-primary text-white font-bold py-2 px-4 rounded hover:bg-brand-secondary transition-colors">
              Go to Main App
            </a>
          </div>
        </div>
    );

    if (!encodedData) {
      return <ErrorDisplay message="The link you followed is incomplete." />;
    }

    try {
      // Decode URL-safe base64 and handle UTF-8 characters.
      const urlSafeBase64ToStr = (base64Url: string): string => {
        let base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
        const padding = '='.repeat((4 - base64.length % 4) % 4);
        base64 += padding;

        const binaryStr = atob(base64);
        const uint8Array = new Uint8Array(binaryStr.length);
        for (let i = 0; i < binaryStr.length; i++) {
            uint8Array[i] = binaryStr.charCodeAt(i);
        }
        return new TextDecoder().decode(uint8Array);
      };

      const decodedJson = urlSafeBase64ToStr(encodedData);
      const snapshotPayload: { monthYear: string; data: MonthlyData } = JSON.parse(decodedJson);

      if (snapshotPayload && snapshotPayload.monthYear && snapshotPayload.data) {
        return <Snapshot snapshotData={snapshotPayload} />;
      } else {
        throw new Error("Invalid data structure");
      }
    } catch (error) {
      console.error("Failed to decode snapshot data:", error);
      return <ErrorDisplay message="The link you followed appears to be corrupted or invalid." />;
    }
  }

  const { user, loading } = useAuth();

  if (loading) {
    return <LoadingScreen />;
  }

  if (!user) {
    return <AuthScreen />;
  }

  return <MainApp />;
}

