                Financial Profile:
                ${financialProfile}

                Your response MUST be valid JSON according to the schema.`
            }]
        }],
        config: {
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.4 // Lower temperature for more consistent financial logic
        }
      });

