import React, { useState, useEffect } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { MonthlyData } from '../types';
import { calculateNetWorth, calculateMonthlyIncome, formatCurrency, calculateTotalBalance } from '../utils/helpers';
import Button from './ui/Button';
import { SparklesIcon, InfoIcon } from './ui/Icons';
import Card from './ui/Card';

interface RecommendationsModalProps {
  isOpen: boolean;
  onClose: () => void;
  data: MonthlyData;
  monthYear: string;
}

interface Recommendation {
  title: string;
  description: string;
  category: string;
  actionItem: string;
}

/**
 * FIX: Re-declared global window extensions to match existing environment definitions.
 * Use optional chaining or checks at runtime since these might not be present.
 */
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    readonly aistudio?: AIStudio;
  }
}

const RecommendationsModal: React.FC<RecommendationsModalProps> = ({ isOpen, onClose, data, monthYear }) => {
  const [loading, setLoading] = useState(false);
  const [recommendations, setRecommendations] = useState<Recommendation[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);

  useEffect(() => {
    // Reset state when the modal opens or month changes
    if (isOpen) {
        setRecommendations(null);
        setError(null);
        setNeedsKey(false);
    }
  }, [monthYear, isOpen]);

  useEffect(() => {
    const checkKeyAndFetch = async () => {
        if (isOpen && !recommendations && !loading && !error && !needsKey) {
            // Defensive check: only use aistudio helpers if they exist
            if (window.aistudio) {
                try {
                    const hasKey = await window.aistudio.hasSelectedApiKey();
                    if (!hasKey) {
                        setNeedsKey(true);
                    } else {
                        fetchRecommendations();
                    }
                } catch (err) {
                    console.warn("AI Studio key check failed, attempting direct fetch:", err);
                    fetchRecommendations();
                }
            } else {
                // If window.aistudio is missing, proceed directly (environment might provide key differently)
                fetchRecommendations();
            }
        }
    };
    checkKeyAndFetch();
  }, [isOpen, recommendations, loading, error, needsKey]);

  const handleConnectKey = async () => {
      if (window.aistudio) {
          try {
              await window.aistudio.openSelectKey();
              setNeedsKey(false);
              // After triggering the key selection, we proceed
              fetchRecommendations();
          } catch (err) {
              console.error("Failed to open key selection:", err);
              setError("Could not open the API key selection dialog.");
          }
      } else {
          setError("API key helper not found in this environment.");
      }
  };

  const fetchRecommendations = async () => {
    // Basic validation of the key before even trying the SDK
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        setNeedsKey(true);
        return;
    }

    setLoading(true);
    setError(null);

    try {
      const netWorth = calculateNetWorth(data);
      const income = calculateMonthlyIncome(data.income.jobs);
      const totalDebt = calculateTotalBalance(data.creditCards) + calculateTotalBalance(data.loans);

      const scores = Object.entries(data.creditScores)
         .map(([key, val]) => {
             const score = typeof val === 'object' && val !== null && 'score8' in val ? (val as any).score8 : val;
             return `${key}: ${score}`;
         })
         .join(', ');

      const financialProfile = `
        Target Month: ${monthYear}
        Current Net Worth: ${formatCurrency(netWorth)}
        Total Monthly Income: ${formatCurrency(income)}
        Total Debt Balance: ${formatCurrency(totalDebt)}
        Credit Score Profile: ${scores}
        Asset Breakdown: ${data.assets.map(a => `${a.name} ($${a.value})`).join(', ')}
        Liability Breakdown: ${[...data.creditCards, ...data.loans].map(l => `${l.name} ($${l.balance})`).join(', ')}
      `;

      // Initialize API inside the function to ensure the most up-to-date key
      const ai = new GoogleGenAI({ apiKey });

      const schema = {
        type: Type.OBJECT,
        properties: {
            recommendations: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        category: { type: Type.STRING, description: "Must be one of: 'Credit Cards', 'Loans', 'Savings', 'Investments', 'General'" },
                        actionItem: { type: Type.STRING, description: "A short, actionable step (max 15 words)." }
                    },
                    required: ['title', 'description', 'category', 'actionItem']
                }
            }
        },
        required: ['recommendations']
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{
            parts: [{
                text: `You are a world-class senior financial advisor. Analyze the following financial profile for ${monthYear} and provide 4-5 high-impact, tailored recommendations.

                Analysis Goals:
                1. Debt Optimization: Identify if high interest debt can be consolidated or moved to better products.
                2. Wealth Accumulation: Suggest savings or investment strategies based on current assets and income.
                3. Credit Health: Point out specific bureaus where scores are lagging and how to improve.

                Financial Profile:
                ${financialProfile}

                Your response MUST be valid JSON according to the schema.`
            }]
        }],
        config: {
            responseMimeType: "application/json",
            responseSchema: schema,
            temperature: 0.4
        }
      });

      const text = response.text;
      if (text) {
          try {
              const parsed = JSON.parse(text);
              if (parsed.recommendations && Array.isArray(parsed.recommendations)) {
                  setRecommendations(parsed.recommendations);
              } else {
                  throw new Error("Invalid response format: Missing recommendations array");
              }
          } catch (parseErr) {
              console.error("Failed to parse AI response:", text);
              setError("The AI returned an invalid response format. Please try again.");
          }
      } else {
          setError("No recommendations could be generated at this time.");
      }

    } catch (err: any) {
      console.error("AI Generation Error:", err);

      // Handle key-related errors by prompting for key selection if available
      if (err.message?.includes('Requested entity was not found') || 
          err.message?.includes('API key') || 
          err.message?.includes('403') || 
          err.message?.includes('401')) {

          if (window.aistudio) {
              setNeedsKey(true);
          } else {
              setError("API key is invalid or missing. Please ensure your environment is configured correctly.");
          }
          return;
      }

      setError("Failed to connect to the AI advisor. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex justify-center items-center p-4">
      <div className="bg-white dark:bg-gray-900 rounded-lg shadow-xl w-full max-w-4xl max-h-[90vh] flex flex-col">
        <div className="p-6 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between bg-gradient-to-r from-purple-50 to-blue-50 dark:from-gray-800 dark:to-gray-800 rounded-t-lg">
           <div className="flex items-center gap-3">
              <div className="p-2 bg-purple-100 dark:bg-purple-900/40 rounded-full text-purple-600 dark:text-purple-300">
                <SparklesIcon />
              </div>
              <div>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-100">AI Financial Recommendations</h2>
                <p className="text-sm text-gray-600 dark:text-gray-400">Analysis for {monthYear}</p>
              </div>
           </div>
           <button onClick={onClose} className="text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 p-2">
             <span className="text-3xl leading-none">&times;</span>
           </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-gray-50 dark:bg-gray-900/50">
           {needsKey ? (
             <div className="text-center py-12 px-4 max-w-md mx-auto">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-purple-100 text-purple-600 mb-6">
                    <SparklesIcon />
                </div>
                <h3 className="text-xl font-bold text-gray-900 dark:text-gray-100 mb-2">Connect Your AI Advisor</h3>
                <p className="text-gray-600 dark:text-gray-400 mb-6">
                    To use high-performance financial analysis, you need to connect an API key from a paid GCP project.
                </p>
                <div className="bg-white dark:bg-gray-800 p-4 rounded-xl border border-gray-200 dark:border-gray-700 mb-8 text-left">
                    <h4 className="text-sm font-bold mb-2">Instructions:</h4>
                    <ul className="text-xs text-gray-600 dark:text-gray-400 space-y-2 list-disc pl-4">
                        <li>Click "Connect API Key" below.</li>
                        <li>Select a key from a project with billing enabled.</li>
                        <li>Learn more about <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="text-brand-primary underline">Gemini API billing</a>.</li>
                    </ul>
                </div>
                <div className="flex flex-col gap-3">
                    <Button onClick={handleConnectKey} className="w-full py-4">
                        <SparklesIcon /> Connect API Key
                    </Button>
                    <Button onClick={onClose} variant="secondary">Cancel</Button>
                </div>
             </div>
           ) : loading ? (
             <div className="flex flex-col items-center justify-center h-64 space-y-4">
               <div className="relative">
                 <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-purple-600"></div>
                 <div className="absolute inset-0 flex items-center justify-center">
                    <SparklesIcon />
                 </div>
               </div>
               <div className="text-center">
                 <p className="text-purple-600 dark:text-purple-400 font-bold animate-pulse text-lg">Processing your financial data...</p>
                 <p className="text-xs text-gray-500 mt-1">Our AI is running complex simulations to find your best path.</p>
               </div>
             </div>
           ) : error ? (
