    try {
      // Guidelines: Access key exclusively from process.env.API_KEY
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Build Profile String
      const netWorth = calculateNetWorth(data);
      const income = calculateMonthlyIncome(data.income.jobs);
      const totalDebt = calculateTotalBalance(data.creditCards) + calculateTotalBalance(data.loans);

      const scores = Object.entries(data.creditScores)
         .map(([key, val]) => {
             const score = typeof val === 'object' && val !== null && 'score8' in val ? (val as any).score8 : val;
             return `${key}: ${score}`;
         })
         .join(', ');

      const financialProfile = `
        Target Month: ${monthYear}
        Current Net Worth: ${formatCurrency(netWorth)}
        Total Monthly Income: ${formatCurrency(income)}
        Total Debt Balance: ${formatCurrency(totalDebt)}
        Credit Score Profile: ${scores}
        Asset Breakdown: ${data.assets.map(a => `${a.name} ($${a.value})`).join(', ')}
        Liability Breakdown: ${[...data.creditCards, ...data.loans].map(l => `${l.name} ($${l.balance})`).join(', ')}
      `;

      // Schema for recommendations
      const schema = {
        type: Type.OBJECT,
        properties: {
            recommendations: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        category: { type: Type.STRING, description: "One of: 'Credit Cards', 'Loans', 'Savings', 'Investments', 'General'" },
                        actionItem: { type: Type.STRING, description: "Maximum 15 words." }
                    },
                    required: ['title', 'description', 'category', 'actionItem']
                }
            }
        },
        required: ['recommendations']
      };

      // Complex Reasoning: gemini-3-pro-preview
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `You are a world-class senior financial advisor. Analyze this snapshot for ${monthYear} and provide 4-5 high-impact recommendations.
Profile:
${financialProfile}
Return JSON according to schema.`,
        config: {
            responseMimeType: "application/json",
            responseSchema: schema,
            thinkingConfig: { thinkingBudget: 32768 }
        }
      });

      const text = response.text;
      if (text) {
          const parsed = JSON.parse(text);
          if (parsed.recommendations && Array.isArray(parsed.recommendations)) {
              setRecommendations(parsed.recommendations);
          } else {
              throw new Error("UNEXPECTED_RESPONSE_FORMAT");
          }
      } else {
          throw new Error("EMPTY_RESPONSE");
      }

    } catch (err: any) {
      console.error("AI Advisor Error:", err);

      const isConfigError = !process.env.API_KEY || 
                           err.message?.toLowerCase().includes('api key') || 
                           err.message?.includes('403') || 
                           err.message?.includes('401');

      if (isConfigError) {
          if ((window as any).aistudio) {
              setNeedsKey(true);
          } else {
              setError("API configuration is missing or invalid in the environment. If you're hosting on Render.com, ensure that the environment variable 'API_KEY' is correctly set in your project settings and that it is available to the client bundle.");
          }
          return;
      }

      setError("The AI advisor encountered an issue analyzing your data. Please check your network and try again.");
    } finally {
      setLoading(false);
    }
  };
