export type AppUser = User;

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { onAuthStateChanged, GoogleAuthProvider, signInWithPopup, signOut, signInAnonymously } from 'firebase/auth';
import { auth } from '../firebase';
import type { AppUser } from '../types';

interface AuthContextType {
  user: AppUser | null;
  loading: boolean;
  loginWithGoogle: () => Promise<void>;
  loginAsGuest: () => Promise<void>;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<AppUser | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      setUser(firebaseUser);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const loginWithGoogle = async () => {
    const provider = new GoogleAuthProvider();
    provider.setCustomParameters({ prompt: 'select_account' });

    try {
      setLoading(true);
      await signInWithPopup(auth, provider);
    } catch (error: any) {
      console.error("Google sign-in error", error);
      let errorMessage = "An unknown error occurred during sign-in.";
      if (error.code) {
        switch (error.code) {
          case 'auth/popup-closed-by-user':
            errorMessage = "Sign-in window closed. Please try again.";
            break;
          case 'auth/popup-blocked':
            errorMessage = "Popup blocked! Please allow popups for this site.";
            break;
          default:
            errorMessage = error.message;
        }
      }
      throw new Error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const loginAsGuest = async () => {
    try {
      setLoading(true);
      await signInAnonymously(auth);
    } catch (error: any) {
      console.error("Anonymous sign-in error", error);
      throw new Error("Failed to start guest session. Please check your connection.");
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    try {
      setLoading(true);
      await signOut(auth);
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  const value = { user, loading, loginWithGoogle, loginAsGuest, logout };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import { useState, useEffect, useCallback, useRef } from 'react';
import type { FinancialData, MonthlyData } from '../types';
import { getInitialData, getDummyData } from '../utils/helpers';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../firebase';
import { doc, getDoc, setDoc } from 'firebase/firestore';

export function useFinancialData() {
  const { user } = useAuth();
  const [financialData, setFinancialData] = useState<FinancialData>({});
  const [saveStatus, setSaveStatus] = useState<'saved' | 'unsaved' | 'saving' | 'error'>('saved');
  const [refreshCounter, setRefreshCounter] = useState(0);

  const dataRef = useRef<FinancialData>({});
  const isSavingRef = useRef(false);

  // Sync ref with state when state changes
  useEffect(() => {
    dataRef.current = financialData;
  }, [financialData]);

  // Effect to load data from Firestore whenever the user state changes
  useEffect(() => {
    if (!user) {
      setFinancialData({});
      dataRef.current = {};
      setSaveStatus('saved');
      return;
    }

    setSaveStatus('saving');

    const docRef = doc(db, 'users', user.uid);
    getDoc(docRef).then(docSnap => {
      if (docSnap.exists()) {
        const cloudData = docSnap.data() as FinancialData;
        setFinancialData(cloudData);
        dataRef.current = cloudData;
        setSaveStatus('saved');
      } else {
        // If it's a new anonymous user, give them dummy data to start with (cloud-persisted immediately)
        const initialSeed = user.isAnonymous ? getDummyData() : {};
        setFinancialData(initialSeed);
        dataRef.current = initialSeed;

        // Persist the seed data to Firestore immediately so it's not "just in browser"
        setDoc(docRef, initialSeed)
          .then(() => setSaveStatus('saved'))
          .catch(err => {
            console.error("Error creating initial cloud profile", err);
            setSaveStatus('error');
          });
      }
    }).catch(error => {
      console.error("Error fetching from Database:", error);
      setSaveStatus('error');
    });
  }, [user?.uid]);

  // Save function targeting Firebase Firestore
  const saveData = useCallback(async (): Promise<void> => {
    if (!user || isSavingRef.current) return;

    isSavingRef.current = true;
    setSaveStatus('saving');

    const currentDataToPersist = dataRef.current;

    // Cleanup and sort keys
    const sortedData = Object.keys(currentDataToPersist).sort().reduce((obj, key) => {
        obj[key] = currentDataToPersist[key];
        return obj;
    }, {} as FinancialData);

    try {
      const docRef = doc(db, 'users', user.uid);
      await setDoc(docRef, sortedData);
      setSaveStatus('saved');
      setRefreshCounter(prev => prev + 1);
    } catch (error) {
      console.error("Database persistence error:", error);
      setSaveStatus('error');
      throw error;
    } finally {
      isSavingRef.current = false;
    }
  }, [user]);

  // Autosave when data is marked as unsaved
  useEffect(() => {
    if (saveStatus === 'unsaved') {
      const timer = setTimeout(() => {
        saveData().catch(() => {});
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [financialData, saveStatus, saveData]);

  const updateMonthData = useCallback((monthYear: string, data: MonthlyData) => {
    const nextData = { ...dataRef.current, [monthYear]: data };
    dataRef.current = nextData;
    setFinancialData(nextData);
    setSaveStatus('unsaved');
  }, []);

  const getMonthData = useCallback((monthYear: string): MonthlyData => {
      return financialData[monthYear] || getInitialData();
  }, [financialData]);

  const importData = useCallback(async (jsonString: string) => {
    try {
      const parsedData = JSON.parse(jsonString);
      if (typeof parsedData === 'object' && parsedData !== null) {
        const newData = parsedData as FinancialData;
        dataRef.current = newData;
        setFinancialData(newData);
        setSaveStatus('unsaved');
        // Force an immediate cloud save on import
        await saveData();
        alert('Data successfully synced to the cloud!');
      } else {
        throw new Error("Invalid format");
      }
    } catch (error) {
      console.error("Import failed", error);
      throw error;
    }
  }, [saveData]);

  const exportData = useCallback(() => {
    const jsonString = JSON.stringify(financialData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-cloud-export-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, [financialData]);

  const exportTemplateData = useCallback(() => {
    const templateData: FinancialData = { [new Date().toISOString().split('T')[0].slice(0, 7)]: getInitialData() };
    const jsonString = JSON.stringify(templateData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-template.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, []);

  const hasData = useCallback(() => Object.keys(financialData).length > 0, [financialData]);

  return { 
    financialData, 
    updateMonthData, 
    getMonthData, 
    importData, 
    exportData, 
    hasData, 
    exportTemplateData, 
    saveData, 
    saveStatus,
    refreshCounter
  };
}

import { useState, useEffect, useCallback, useRef } from 'react';
import type { FinancialData, MonthlyData } from '../types';
import { getInitialData, getDummyData } from '../utils/helpers';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../firebase';
import { doc, onSnapshot, setDoc, getDoc } from 'firebase/firestore';

export function useFinancialData() {
  const { user } = useAuth();
  const [financialData, setFinancialData] = useState<FinancialData>({});
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error'>('saved');
  const [refreshCounter, setRefreshCounter] = useState(0);

  const dataRef = useRef<FinancialData>({});
  const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // 1. Real-time Subscription to Firebase
  useEffect(() => {
    if (!user) {
      setFinancialData({});
      dataRef.current = {};
      return;
    }

    const docRef = doc(db, 'users', user.uid);

    // Subscribe to cloud changes
    const unsubscribe = onSnapshot(docRef, (docSnap) => {
      if (docSnap.exists()) {
        const cloudData = docSnap.data() as FinancialData;
        setFinancialData(cloudData);
        dataRef.current = cloudData;
        setSaveStatus('saved');
      } else {
        // Handle new user seeding
        const initialSeed = user.isAnonymous ? getDummyData() : { [new Date().toISOString().slice(0, 7)]: getInitialData() };
        setDoc(docRef, initialSeed);
      }
    }, (error) => {
      console.error("Firestore sync error:", error);
      setSaveStatus('error');
    });

    return () => unsubscribe();
  }, [user?.uid]);

  // 2. Direct Cloud Save Function
  const persistToCloud = useCallback(async (dataToSave: FinancialData) => {
    if (!user) return;

    setSaveStatus('saving');
    try {
      const docRef = doc(db, 'users', user.uid);
      await setDoc(docRef, dataToSave);
      setSaveStatus('saved');
      setRefreshCounter(prev => prev + 1);
    } catch (err) {
      console.error("Cloud save failed:", err);
      setSaveStatus('error');
    }
  }, [user]);

  // 3. Data Update Logic (Database-first)
  const updateMonthData = useCallback((monthYear: string, newData: MonthlyData) => {
    const nextFullData = { ...dataRef.current, [monthYear]: newData };

    // Optimistic UI update
    setFinancialData(nextFullData);
    dataRef.current = nextFullData;

    // Debounced save to prevent database flooding while typing
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => {
      persistToCloud(nextFullData);
    }, 1000);
  }, [persistToCloud]);

  const getMonthData = useCallback((monthYear: string): MonthlyData => {
      return financialData[monthYear] || getInitialData();
  }, [financialData]);

  const importData = useCallback(async (jsonString: string) => {
    try {
      const parsed = JSON.parse(jsonString);
      if (typeof parsed === 'object' && parsed !== null) {
        await persistToCloud(parsed as FinancialData);
        alert('Data successfully merged with your cloud profile!');
      }
    } catch (error) {
      alert('Import failed: Invalid file format.');
    }
  }, [persistToCloud]);

  const exportData = useCallback(() => {
    const jsonString = JSON.stringify(financialData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-cloud-backup-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [financialData]);

  return { 
    financialData, 
    updateMonthData, 
    getMonthData, 
    importData, 
    exportData, 
    hasData: () => Object.keys(financialData).length > 0, 
    exportTemplateData: () => {}, 
    saveStatus,
    refreshCounter,
    saveData: () => persistToCloud(dataRef.current)
  };
}

import React, { useState, useEffect } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import type { MonthlyData } from '../types';
import Button from './ui/Button';
import { SparklesIcon, AlertTriangleIcon, CheckIcon } from './ui/Icons';
import { formatMonthYear, formatCurrency, calculateMonthlyIncome, calculateTotal, calculateTotalBalance, calculateNetWorth, calculateDTI } from '../utils/helpers';

interface RecommendationsModalProps {
  isOpen: boolean;
  onClose: () => void;
  data: MonthlyData;
  monthYear: string;
}

interface RecommendationItem {
  title: string;
  description: string;
  category: string;
  actionItem: string;
}

const RecommendationsModal: React.FC<RecommendationsModalProps> = ({ isOpen, onClose, data, monthYear }) => {
  const [recommendations, setRecommendations] = useState<RecommendationItem[] | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [needsKey, setNeedsKey] = useState(false);

  const fetchRecommendations = async () => {
    setIsLoading(true);
    setError(null);
    setRecommendations(null);

    try {
      // 1. Resolve API Key - prioritize environment variable
      const apiKey = process.env.API_KEY;

      if (!apiKey) {
        // If key is missing, check if we can open the selection dialog
        const aistudio = (window as any).aistudio;
        if (aistudio) {
          setNeedsKey(true);
          setIsLoading(false);
          return;
        }
        throw new Error("API_KEY_NOT_FOUND");
      }

      const ai = new GoogleGenAI({ apiKey });

      const netWorth = calculateNetWorth(data);
      const totalIncome = calculateMonthlyIncome(data.income.jobs);
      const totalBills = calculateTotal(data.monthlyBills);
      const totalDebt = calculateTotalBalance(data.creditCards) + calculateTotalBalance(data.loans);
      const dti = calculateDTI(totalBills, totalIncome);
      const scores = `Experian: ${data.creditScores.experian.score8}, Equifax: ${data.creditScores.equifax.score8}, TransUnion: ${data.creditScores.transunion.score8}`;

      const schema = {
        type: Type.OBJECT,
        properties: {
          recommendations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                category: { type: Type.STRING },
                actionItem: { type: Type.STRING }
              },
              required: ['title', 'description', 'category', 'actionItem']
            }
          }
        },
        required: ['recommendations']
      };

      const prompt = `Analyze this snapshot for ${formatMonthYear(monthYear)}:
        NW: ${formatCurrency(netWorth)}, Income: ${formatCurrency(totalIncome)}, Debt: ${formatCurrency(totalDebt)}, DTI: ${dti.toFixed(1)}%, Scores: ${scores}.
        Provide 4 actionable financial strategies.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: schema,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      });

      const parsed = JSON.parse(response.text || '{}');
      if (parsed.recommendations) setRecommendations(parsed.recommendations);

    } catch (err: any) {
      console.error("Gemini Error:", err);
      if (err.message === "API_KEY_NOT_FOUND") {
        setError("API Key missing. Please check your environment variables or connect a key.");
      } else if (err.message?.includes("API Key must be set")) {
        setNeedsKey(true);
      } else {
        setError("Failed to generate advice. Check your connection.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectKey = async () => {
    const aistudio = (window as any).aistudio;
    if (aistudio?.openSelectKey) {
      await aistudio.openSelectKey();
      setNeedsKey(false);
      fetchRecommendations();
    }
  };

  useEffect(() => {
    if (isOpen) fetchRecommendations();
  }, [isOpen, monthYear]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex justify-center items-center p-4">
      <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[85vh] overflow-hidden flex flex-col border border-purple-100 dark:border-purple-900/30">
        <div className="p-6 border-b flex items-center justify-between bg-gradient-to-r from-purple-50 to-white dark:from-purple-900/10 dark:to-gray-900">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-purple-100 dark:bg-purple-900/40 rounded-xl"><SparklesIcon /></div>
