      } else {
        setError("Failed to generate tailored insights. Please verify your internet connection or check API logs.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setNeedsKey(false);
      fetchRecommendations();
    }
  };

