        </div>

        {/* Footer */}
        <div className="p-4 border-t bg-gray-50 dark:bg-gray-800/50 flex justify-end gap-3">
          {advisorMode === 'ai' && (
            <Button onClick={() => setRecommendations(getLocalRecommendations(data)) || setAdvisorMode('local')} variant="secondary" size="small">
