const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<(AppUser & { isMock?: boolean }) | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        setUser(firebaseUser);
      } else if (!user?.isMock) {
        // Only clear if we aren't in a mock guest session
        setUser(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, [user?.isMock]);

  const loginWithGoogle = async () => {
    const provider = new GoogleAuthProvider();
    provider.setCustomParameters({ prompt: 'select_account' });

    try {
      setLoading(true);
      await signInWithPopup(auth, provider);
    } catch (error: any) {
      console.error("Google sign-in error", error);
      let errorMessage = "An unknown error occurred during sign-in.";
      if (error.code) {
        switch (error.code) {
          case 'auth/popup-closed-by-user':
            errorMessage = "Sign-in window closed. Please try again.";
            break;
          case 'auth/popup-blocked':
            errorMessage = "Popup blocked! Please allow popups for this site.";
            break;
          default:
            errorMessage = error.message;
        }
      }
      throw new Error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const loginAsGuest = async () => {
    try {
      setLoading(true);
      // Try real Firebase Anonymous Auth first
      await signInAnonymously(auth);
    } catch (error: any) {
      console.warn("Firebase Anonymous Auth failed or is disabled. Falling back to local Guest Mode.", error);

      // Fallback: Create a mock user object to bypass AuthScreen
      // This ensures "nothing happens" never occurs even if Firebase config is restrictive
      const mockUser = {
        uid: 'local-guest-' + Math.random().toString(36).substr(2, 9),
        isAnonymous: true,
        isMock: true,
        displayName: 'Guest User',
        email: null,
        photoURL: null,
      } as any;

      setUser(mockUser);
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    try {
      setLoading(true);
      if (!user?.isMock) {
        await signOut(auth);
      }
      setUser(null);
    } finally {
      setLoading(false);
    }
  };

  const value = { user, loading, loginWithGoogle, loginAsGuest, logout };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import { useState, useEffect, useCallback, useRef } from 'react';
import type { FinancialData, MonthlyData } from '../types';
import { getInitialData, getDummyData } from '../utils/helpers';
import { useAuth } from '../contexts/AuthContext';
import { db } from '../firebase';
import { doc, onSnapshot, setDoc } from 'firebase/firestore';

const LOCAL_STORAGE_KEY = 'wmcw_local_guest_data';

export function useFinancialData() {
  const { user } = useAuth();
  const [financialData, setFinancialData] = useState<FinancialData>({});
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error'>('saved');
  const [refreshCounter, setRefreshCounter] = useState(0);

  const dataRef = useRef<FinancialData>({});
  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // 1. Data Subscription (Firebase OR LocalStorage)
  useEffect(() => {
    if (!user) {
      setFinancialData({});
      dataRef.current = {};
      return;
    }

    // Handle Mock Guest (Local Storage Only)
    if (user.isMock) {
      const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
      if (localData) {
        const parsed = JSON.parse(localData);
        setFinancialData(parsed);
        dataRef.current = parsed;
      } else {
        const seed = getDummyData();
        setFinancialData(seed);
        dataRef.current = seed;
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(seed));
      }
      setSaveStatus('saved');
      return;
    }

    // Handle Firebase User
    const docRef = doc(db, 'users', user.uid);
    const unsubscribe = onSnapshot(docRef, async (docSnap) => {
      if (docSnap.exists()) {
        const cloudData = docSnap.data() as FinancialData;
        setFinancialData(cloudData);
        dataRef.current = cloudData;
        setSaveStatus('saved');
      } else {
        console.log("Seeding initial data for Firebase user:", user.uid);
        const initialSeed = user.isAnonymous 
            ? getDummyData() 
            : { [new Date().toISOString().slice(0, 7)]: getInitialData() };

        try {
          await setDoc(docRef, initialSeed);
        } catch (err) {
          console.error("Failed to seed initial data:", err);
          setSaveStatus('error');
        }
      }
    }, (error) => {
      console.error("Firestore sync error:", error);
      setSaveStatus('error');
    });

    return () => unsubscribe();
  }, [user?.uid, user?.isMock]);

  // 2. Direct Persist Function
  const persistData = useCallback(async (dataToSave: FinancialData) => {
    if (!user) return;

    setSaveStatus('saving');
    try {
      if (user.isMock) {
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(dataToSave));
        setSaveStatus('saved');
      } else {
        const docRef = doc(db, 'users', user.uid);
        await setDoc(docRef, dataToSave);
        setSaveStatus('saved');
      }
      setRefreshCounter(prev => prev + 1);
    } catch (err) {
      console.error("Save failed:", err);
      setSaveStatus('error');
    }
  }, [user]);

  // 3. Data Update Logic
  const updateMonthData = useCallback((monthYear: string, newData: MonthlyData) => {
    const nextFullData = { ...dataRef.current, [monthYear]: newData };

    setFinancialData(nextFullData);
    dataRef.current = nextFullData;

    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => {
      persistData(nextFullData);
    }, 1000);
  }, [persistData]);

  const getMonthData = useCallback((monthYear: string): MonthlyData => {
      return financialData[monthYear] || getInitialData();
  }, [financialData]);

  const importData = useCallback(async (jsonString: string) => {
    try {
      const parsed = JSON.parse(jsonString);
      if (typeof parsed === 'object' && parsed !== null) {
        await persistData(parsed as FinancialData);
        alert('Data successfully imported!');
      }
    } catch (error) {
      alert('Import failed: Invalid file format.');
    }
  }, [persistData]);

  const exportData = useCallback(() => {
    const jsonString = JSON.stringify(financialData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-backup-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [financialData]);

  return { 
    financialData, 
    updateMonthData, 
    getMonthData, 
    importData, 
    exportData, 
    hasData: () => Object.keys(financialData).length > 0, 
    exportTemplateData: () => {}, 
    saveStatus,
    refreshCounter,
    saveData: () => persistData(dataRef.current)
  };
}

