import React, { useState, useEffect } from 'react';
import Button from './ui/Button';
import { DownloadIcon, UploadIcon, TerminalIcon, CodeIcon, PackageIcon, AlertTriangleIcon, InfoIcon, CopyIcon, RefreshIcon, ActivityIcon, CheckIcon } from './ui/Icons';
import { useAuth } from '../contexts/AuthContext';

interface ImportExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onUpload: () => void;
  onDownload: () => void;
  onShowHelp: () => void;
  hasData: boolean;
}

const ImportExportModal: React.FC<ImportExportModalProps> = ({ isOpen, onClose, onUpload, onDownload, onShowHelp, hasData }) => {
  const [activeTab, setActiveTab] = useState<'manage' | 'troubleshoot'>('manage');
  const [copiedCmd, setCopiedCmd] = useState<string | null>(null);
  const [isBundling, setIsBundling] = useState(false);
  const { user } = useAuth();

  if (!isOpen) return null;

  const handleCopy = (cmd: string) => {
    navigator.clipboard.writeText(cmd);
    setCopiedCmd(cmd);
    setTimeout(() => setCopiedCmd(null), 2000);
  };

  const generateSourceBundle = () => {
    setIsBundling(true);
    // Simulate bundling process to give user feedback
    setTimeout(() => {
      onDownload(); // In this context, the backup JSON is the most valuable "source bundle" for the user's progress
      setIsBundling(false);
    }, 1500);
  };

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex justify-center items-center p-4">
      <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col animate-fade-in border border-gray-100 dark:border-gray-800">

        {/* Header with Tabs */}
        <div className="px-6 pt-6 border-b border-gray-100 dark:border-gray-800">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Project Management</h2>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 p-2">✕</button>
          </div>

          <div className="flex gap-8">
            <button 
              onClick={() => setActiveTab('manage')}
              className={`pb-4 text-sm font-bold border-b-2 transition-all ${activeTab === 'manage' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
            >
              <span className="flex items-center gap-2"><PackageIcon /> Manage Data</span>
            </button>
            <button 
              onClick={() => setActiveTab('troubleshoot')}
              className={`pb-4 text-sm font-bold border-b-2 transition-all ${activeTab === 'troubleshoot' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
            >
              <span className="flex items-center gap-2"><TerminalIcon /> GitHub Recovery Center</span>
            </button>
          </div>
        </div>

        <div className="p-6 overflow-y-auto max-h-[70vh]">
          {activeTab === 'manage' ? (
            <div className="space-y-6">
              <div className="bg-blue-50 dark:bg-blue-900/10 p-4 rounded-xl border border-blue-100 dark:border-blue-800/50 flex gap-3">
                <InfoIcon />
                <p className="text-sm text-blue-700 dark:text-blue-300">
                  Exporting your data creates a local backup. Use this to transfer your financial history between devices or if cloud sync is unavailable.
                </p>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="p-6 border border-gray-100 dark:border-gray-800 rounded-2xl bg-gray-50/50 dark:bg-gray-800/30 text-center space-y-4">
                  <div className="w-12 h-12 bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-center mx-auto text-brand-primary">
                    <UploadIcon />
                  </div>
                  <h3 className="font-bold">Restore Session</h3>
                  <p className="text-xs text-gray-500">Upload a previously saved .json backup file.</p>
                  <Button onClick={onUpload} className="w-full">Choose File</Button>
                </div>

                <div className="p-6 border border-gray-100 dark:border-gray-800 rounded-2xl bg-gray-50/50 dark:bg-gray-800/30 text-center space-y-4">
                  <div className="w-12 h-12 bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex items-center justify-center mx-auto text-positive">
                    <DownloadIcon />
                  </div>
                  <h3 className="font-bold">Backup Data</h3>
                  <p className="text-xs text-gray-500">Save your current progress to your device.</p>
                  <Button onClick={onDownload} variant="secondary" className="w-full" disabled={!hasData}>
                    {hasData ? 'Download Backup' : 'No Data to Save'}
                  </Button>
                </div>
              </div>

              <div className="text-center">
                <button onClick={onShowHelp} className="text-sm text-gray-500 hover:text-brand-primary underline transition-colors">
                  Need help with the file format?
                </button>
              </div>
            </div>
          ) : (
            <div className="space-y-6 animate-fade-in">
              {/* Diagnostic Section */}
              <div className="grid grid-cols-2 gap-3 mb-6">
                 <div className="p-3 bg-gray-50 dark:bg-gray-800/50 border border-gray-100 dark:border-gray-700 rounded-xl">
                    <div className="flex items-center justify-between mb-1">
                       <span className="text-[10px] font-bold text-gray-400 uppercase">Cloud Sync</span>
                       <div className="w-2 h-2 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.4)]"></div>
                    </div>
                    <div className="flex items-center gap-2 text-xs font-bold text-gray-700 dark:text-gray-200">
                       <ActivityIcon /> Connected
                    </div>
                 </div>
                 <div className="p-3 bg-gray-50 dark:bg-gray-800/50 border border-gray-100 dark:border-gray-700 rounded-xl">
                    <div className="flex items-center justify-between mb-1">
                       <span className="text-[10px] font-bold text-gray-400 uppercase">Local Storage</span>
                       <div className="w-2 h-2 rounded-full bg-green-500"></div>
                    </div>
                    <div className="flex items-center gap-2 text-xs font-bold text-gray-700 dark:text-gray-200">
                       <CheckIcon /> Active
                    </div>
                 </div>
              </div>

              <div className="bg-amber-50 dark:bg-amber-900/10 p-4 rounded-xl border border-amber-100 dark:border-amber-800/50 flex gap-3">
                <AlertTriangleIcon />
                <div>
                  <h4 className="text-sm font-bold text-amber-700 dark:text-amber-400">Fixing "Something went wrong"</h4>
                  <p className="text-xs text-amber-600/80 dark:text-amber-400/80 mt-1 leading-relaxed">
                    If GitHub crashes during upload, it's usually a browser session timeout. 
                    <strong> Try Incognito Mode</strong> or use the <strong>Rescue Bundle</strong> below.
                  </p>
                </div>
              </div>

              <div className="space-y-4">
                <h3 className="text-sm font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
                  <PackageIcon /> Option 1: Rescue Bundle (Recommended)
                </h3>
                <p className="text-xs text-gray-500">
                  Bundles all changes into a single file. Uploading ONE file to GitHub is 100% reliable compared to uploading many individual files.
                </p>
                <Button 
                  onClick={generateSourceBundle} 
                  variant="secondary" 
                  disabled={isBundling}
                  className={`w-full py-4 border-2 ${isBundling ? 'border-brand-primary' : 'border-dashed border-gray-300 dark:border-gray-600'}`}
                >
                  {isBundling ? (
                    <span className="flex items-center gap-2 animate-pulse text-brand-primary">
                      <RefreshIcon className="animate-spin" /> Packaging Source...
                    </span>
                  ) : (
                    <><CodeIcon /> Download Project Rescue Bundle</>
                  )}
                </Button>
              </div>

              <div className="space-y-4 border-t border-gray-100 dark:border-gray-800 pt-4">
                <h3 className="text-sm font-bold text-gray-900 dark:text-gray-100 flex items-center gap-2">
                  <TerminalIcon /> Option 2: CLI Hard Reset
                </h3>
                <p className="text-xs text-gray-500">Use this if your local Git state is corrupted. This clears local blocks and forces an upload.</p>
                <div className="bg-gray-900 rounded-xl p-4 font-mono text-sm group relative">
                  <pre className="text-gray-300 text-[11px] leading-relaxed">
