            </Card>
            <Card title="Monthly Bills">
                <ul className="space-y-2 text-sm">
                    {data.monthlyBills.map(bill => (
                        <li key={bill.id} className="flex justify-between">
                            <span>{bill.name}</span>
                            <span className="font-semibold">{formatCurrency(bill.amount)}</span>
