                    ))}
                    <li className="flex justify-between border-t pt-2 mt-2 font-bold text-base">
                        <span>Total Bills</span>
                        <span>{formatCurrency(totalBills)}</span>
                    </li>
                </ul>
            </Card>
        </div>

        <SimulationModal 
            isOpen={isSimulationOpen}
            onClose={() => setIsSimulationOpen(false)}
            data={data}
            monthYear={monthYear}
        />
    </div>
  );
};

