        type: Type.OBJECT,
        properties: {
          experian: { type: Type.INTEGER },
          equifax: { type: Type.INTEGER },
          transunion: { type: Type.INTEGER },
          reasoning: { type: Type.STRING, description: "Clear explanation of why the scores changed." },
          recommendations: {
            type: Type.ARRAY,
