      if (localData) {
        const parsed = JSON.parse(localData);
        setFinancialData(parsed);
        dataRef.current = parsed;
      } else {
        const seed = getDummyData();
        setFinancialData(seed);
        dataRef.current = seed;
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(seed));
      }
      setSaveStatus('saved');
      return;
    }

    // Handle Firebase User
    const docRef = doc(db, 'users', user.uid);
    const unsubscribe = onSnapshot(docRef, async (docSnap) => {
      if (docSnap.exists()) {
        const cloudData = docSnap.data() as FinancialData;
        setFinancialData(cloudData);
        dataRef.current = cloudData;
        setSaveStatus('saved');
      } else {
        console.log("Seeding initial data for Firebase user:", user.uid);
        const initialSeed = user.isAnonymous 
            ? getDummyData() 
            : { [new Date().toISOString().slice(0, 7)]: getInitialData() };

        try {
          await setDoc(docRef, initialSeed);
        } catch (err) {
          console.error("Failed to seed initial data:", err);
          setSaveStatus('error');
        }
      }
    }, (error) => {
      console.error("Firestore sync error:", error);
      setSaveStatus('error');
    });

    return () => unsubscribe();
  }, [user?.uid, user?.isMock]);

  // 2. Direct Persist Function
  const persistData = useCallback(async (dataToSave: FinancialData) => {
    if (!user) return;

    setSaveStatus('saving');
    try {
      if (user.isMock) {
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(dataToSave));
        setSaveStatus('saved');
      } else {
        const docRef = doc(db, 'users', user.uid);
        await setDoc(docRef, dataToSave);
        setSaveStatus('saved');
      }
      setRefreshCounter(prev => prev + 1);
    } catch (err) {
      console.error("Save failed:", err);
      setSaveStatus('error');
    }
  }, [user]);

  // 3. Data Update Logic
  const updateMonthData = useCallback((monthYear: string, newData: MonthlyData) => {
    const nextFullData = { ...dataRef.current, [monthYear]: newData };

    setFinancialData(nextFullData);
    dataRef.current = nextFullData;

    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => {
      persistData(nextFullData);
    }, 1000);
  }, [persistData]);

  const getMonthData = useCallback((monthYear: string): MonthlyData => {
      return financialData[monthYear] || getInitialData();
  }, [financialData]);

  const importData = useCallback(async (jsonString: string) => {
    try {
      const parsed = JSON.parse(jsonString);
      if (typeof parsed === 'object' && parsed !== null) {
        await persistData(parsed as FinancialData);
        alert('Data successfully imported!');
      }
    } catch (error) {
      alert('Import failed: Invalid file format.');
    }
  }, [persistData]);

  const exportData = useCallback(() => {
    const jsonString = JSON.stringify(financialData, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `wmcw-backup-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [financialData]);

  const clearCloudData = useCallback(async () => {
    if (!user) return;
    try {
      if (user.isMock) {
        localStorage.removeItem(LOCAL_STORAGE_KEY);
      } else {
        const docRef = doc(db, 'users', user.uid);
        await deleteDoc(docRef);
      }
      setFinancialData({});
      dataRef.current = {};
      setRefreshCounter(prev => prev + 1);
    } catch (err) {
      console.error("Failed to clear data:", err);
      throw err;
    }
  }, [user]);

  return { 
    financialData, 
    updateMonthData, 
    getMonthData, 
    importData, 
    exportData, 
    clearCloudData,
    hasData: () => Object.keys(financialData).length > 0, 
    exportTemplateData: () => {}, 
    saveStatus,
    refreshCounter,
    saveData: () => persistData(dataRef.current)
  };
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { 
  onAuthStateChanged, 
  GoogleAuthProvider, 
  signInWithPopup, 
  signInWithRedirect, 
  getRedirectResult, 
  signOut, 
  signInAnonymously,
  setPersistence,
  browserLocalPersistence,
  deleteUser
} from 'firebase/auth';
import { auth } from '../firebase';
import type { AppUser } from '../types';

interface AuthContextType {
  user: AppUser | null;
  loading: boolean;
  isPremium: boolean;
  isSuperUser: boolean;
  loginWithGoogle: () => Promise<void>;
  loginAsGuest: () => Promise<void>;
  logout: () => Promise<void>;
  upgradeToPremium: () => void;
  deleteUserAccount: () => Promise<void>;
}

const SUPER_USER_EMAILS = [
  'reach_dlaniger@hotmail.com',
  'dlaniger.napm.consulting@gmail.com'
];

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<AppUser | null>(null);
  const [loading, setLoading] = useState(true);
  const [isPremium, setIsPremium] = useState(false);

  const isSuperUser = user?.email ? SUPER_USER_EMAILS.includes(user.email) : false;

  // Set persistence to LOCAL so it survives session clearing on mobile browsers
  useEffect(() => {
    setPersistence(auth, browserLocalPersistence).catch(err => console.error("Persistence error:", err));
  }, []);

  useEffect(() => {
    // Check for redirect result on mount (crucial for mobile flow)
    getRedirectResult(auth).then((result) => {
      if (result?.user) {
        console.log("Redirect sign-in successful");
      }
    }).catch((error) => {
      console.error("Redirect sign-in error:", error);
    });

    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        const appUser = firebaseUser as AppUser;
        setUser(appUser);
        const isAdmin = SUPER_USER_EMAILS.includes(firebaseUser.email || '');
        const localPremium = localStorage.getItem(`premium_${firebaseUser.uid}`) === 'true';
        setIsPremium(localPremium || isAdmin);
      } else {
        setUser(null);
        setIsPremium(false);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const loginWithGoogle = async () => {
    const provider = new GoogleAuthProvider();
    provider.setCustomParameters({ prompt: 'select_account' });

    // Check if user is on mobile to use Redirect instead of Popup
    const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

    try {
      setLoading(true);
      if (isMobile) {
        // Redirect is much more reliable on Android WebViews and mobile browsers
        await signInWithRedirect(auth, provider);
      } else {
        const result = await signInWithPopup(auth, provider);
        if (result.user) {
          const isAdmin = SUPER_USER_EMAILS.includes(result.user.email || '');
          setIsPremium(isAdmin || localStorage.getItem(`premium_${result.user.uid}`) === 'true');
        }
      }
    } catch (err) {
      console.error("Google login failed:", err);
      throw err;
    } finally {
      // Don't set loading false for mobile as it's redirecting away
      if (!isMobile) setLoading(false);
    }
  };

  const loginAsGuest = async () => {
    setLoading(true);
    const mockUser = {
      uid: 'guest-' + Math.random().toString(36).substr(2, 9),
      isAnonymous: true,
      isMock: true,
      displayName: 'Guest User',
      email: null,
    } as AppUser;

    try {
      await signInAnonymously(auth);
    } catch (e) {
      setUser(mockUser);
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    try {
      setLoading(true);
      if (user && !user.isMock) await signOut(auth);
      setUser(null);
      setIsPremium(false);
    } finally {
      setLoading(false);
    }
  };

  const deleteUserAccount = async () => {
    const currentUser = auth.currentUser;
    if (!currentUser) return;
    try {
      await deleteUser(currentUser);
    } catch (err: any) {
      if (err.code === 'auth/requires-recent-login') {
        alert("This operation is sensitive and requires a recent login. Please sign out and sign back in before deleting your account.");
      }
      throw err;
    }
  };

  const upgradeToPremium = () => {
    if (user) {
      localStorage.setItem(`premium_${user.uid}`, 'true');
      setIsPremium(true);
    }
  };

  const value = { 
    user, 
    loading, 
    isPremium: isPremium || isSuperUser, 
    isSuperUser,
    loginWithGoogle, 
    loginAsGuest, 
    logout,
    upgradeToPremium,
    deleteUserAccount
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) throw new Error('useAuth must be used within an AuthProvider');
  return context;
};

