            </p>
          </div>

          {/* Core Actions */}
          <div className="grid grid-cols-1 gap-4">
            <div className="p-4 border border-gray-100 dark:border-gray-800 rounded-xl bg-gray-50/50 dark:bg-gray-800/30 flex items-center justify-between">
