/**
 * NEW: Async Snapshot Loader
 * This fetches the snapshot data from Firestore using the Short ID.
 */
const SnapshotLoader: React.FC<{ snapshotId: string }> = ({ snapshotId }) => {
  const [snapshot, setSnapshot] = useState<{ monthYear: string; data: MonthlyData } | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchSnapshot = async () => {
      setLoading(true);
      setError(null);

      try {
        // 1. Try treating as Firestore ID (Short URL)
        // We wrap this in its own try/catch to ensure the legacy fallback runs if Firestore fails
        let foundInFirestore = false;
        try {
          const docRef = doc(db, 'shared_snapshots', snapshotId);
          const docSnap = await getDoc(docRef);

          if (docSnap.exists()) {
            setSnapshot(docSnap.data() as any);
            foundInFirestore = true;
          }
        } catch (dbErr) {
          console.warn("Firestore lookup failed, attempting Base64 fallback:", dbErr);
        }

        if (!foundInFirestore) {
          // 2. Fallback: Try decoding as Legacy Base64
          try {
            const urlSafeBase64ToStr = (base64Url: string): string => {
                let base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
                const padding = '='.repeat((4 - base64.length % 4) % 4);
                base64 += padding;
                const binaryStr = atob(base64);
                const uint8Array = new Uint8Array(binaryStr.length);
                for (let i = 0; i < binaryStr.length; i++) {
                    uint8Array[i] = binaryStr.charCodeAt(i);
                }
                return new TextDecoder().decode(uint8Array);
            };
            const decodedJson = urlSafeBase64ToStr(snapshotId);
            const legacyData = JSON.parse(decodedJson);
            if (legacyData?.monthYear && legacyData?.data) {
                setSnapshot(legacyData);
            } else {
                throw new Error("Invalid snapshot data structure");
            }
          } catch (e) {
             setError("This snapshot link is invalid or has expired.");
          }
        }
      } catch (err) {
        console.error("Snapshot loader critical error:", err);
        setError("Failed to load snapshot. Please check your connection.");
      } finally {
        setLoading(false);
      }
    };

    fetchSnapshot();
  }, [snapshotId]);

  if (loading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-gray-100 dark:bg-gray-900">
        <Spinner />
        <p className="mt-4 text-gray-500 font-bold uppercase tracking-widest text-xs animate-pulse">Fetching Published Snapshot...</p>
      </div>
    );
  }

  if (error || !snapshot) {
    return (
       <div className="h-screen flex items-center justify-center bg-gray-100 dark:bg-gray-900">
          <div className="text-center p-8 bg-white dark:bg-gray-800 rounded-2xl shadow-xl max-w-md mx-4 border border-red-100">
            <h1 className="text-2xl font-bold text-negative mb-4">Link Expired or Invalid</h1>
            <p className="text-gray-600 dark:text-gray-300 mb-6">{error || "The snapshot you are looking for could not be found."}</p>
             <a href="/" className="inline-block bg-brand-primary text-white font-bold py-3 px-8 rounded-xl hover:bg-brand-secondary transition-all shadow-lg">
              Go to Homepage
            </a>
          </div>
        </div>
    );
  }

  return <Snapshot snapshotData={snapshot} />;
};

const MainApp: React.FC<{ view: View; setView: (v: View) => void }> = ({ view, setView }) => {
  const { financialData, getMonthData, importData, exportData, hasData, exportTemplateData, saveData, saveStatus, refreshCounter } = useFinancialData();
  const { logout } = useAuth();
  const [currentMonthYear, setCurrentMonthYear] = useState(getCurrentMonthYear());
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isUploadHelpOpen, setIsUploadHelpOpen] = useState(false);
  const [isShareModalOpen, setIsShareModalOpen] = useState(false);
  const [isImportExportModalOpen, setIsImportExportModalOpen] = useState(false);
  const [isRecommendationsOpen, setIsRecommendationsOpen] = useState(false);
  const [isDashboardHelpOpen, setIsDashboardHelpOpen] = useState(false);
  const [isSupportOpen, setIsSupportOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentMonthData = useMemo(() => getMonthData(currentMonthYear), [getMonthData, currentMonthYear]);

  const handlePreviousMonth = () => setCurrentMonthYear(prev => getPreviousMonthYear(prev));
  const handleNextMonth = () => setCurrentMonthYear(prev => getNextMonthYear(prev));

  const handleFileImport = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const content = e.target?.result as string;
          importData(content);
        } catch (error) {
          console.error(error);
          alert('Failed to import data. Please check the file format.');
        }
      };
      reader.readAsText(file);
    }
    // Reset file input
    if (fileInputRef.current) {
        fileInputRef.current.value = "";
    }
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  const handleLogout = async () => {
    await logout(); 
  };

  if (view === 'privacy') {
    return <PrivacyPolicy onBack={() => setView('dashboard')} />;
  }

  return (
    <div className="bg-gray-100 dark:bg-gray-900 text-gray-900 dark:text-gray-100 min-h-screen font-sans relative">
      <div className="container mx-auto p-4 md:p-6 lg:p-8">
        <Header 
          currentMonthYear={currentMonthYear}
          onPreviousMonth={handlePreviousMonth}
          onNextMonth={handleNextMonth}
          onEdit={() => setIsEditorOpen(true)}
          onShare={() => setIsShareModalOpen(true)}
          onImportExport={() => setIsImportExportModalOpen(true)}
          onRecommendations={() => setIsRecommendationsOpen(true)}
          view={view === 'dashboard' || view === 'reports' ? view : 'dashboard'}
          setView={setView}
          onLogout={handleLogout}
          onSave={saveData}
          saveStatus={saveStatus}
        />

        <main>
          {view === 'dashboard' && (
            <Dashboard 
              key={`dashboard-${refreshCounter}-${currentMonthYear}`} 
              data={currentMonthData} 
              allData={financialData}
              monthYear={currentMonthYear}
            />
          )}
          {view === 'reports' && (
            <Reports 
              key={`reports-${refreshCounter}`} 
              allData={financialData} 
            />
          )}
        </main>

        <DataEditor 
          isOpen={isEditorOpen}
          onClose={() => setIsEditorOpen(false)}
          monthYear={currentMonthYear}
        />

        <UploadHelpModal 
          isOpen={isUploadHelpOpen}
          onClose={() => setIsUploadHelpOpen(false)}
          onUploadClick={triggerFileUpload}
          exportTemplateData={exportTemplateData}
        />

        <ShareModal
          isOpen={isShareModalOpen}
          onClose={() => setIsShareModalOpen(false)}
          data={currentMonthData}
          monthYear={currentMonthYear}
        />

        <ImportExportModal
            isOpen={isImportExportModalOpen}
            onClose={() => setIsImportExportModalOpen(false)}
            onUpload={() => {
                setIsImportExportModalOpen(false);
                triggerFileUpload();
            }}
            onDownload={() => {
                setIsImportExportModalOpen(false);
                exportData();
            }}
            onShowHelp={() => {
                setIsImportExportModalOpen(false);
                setIsUploadHelpOpen(true);
            }}
            onViewPrivacy={() => {
              setIsImportExportModalOpen(false);
              setView('privacy');
            }}
            hasData={hasData()}
        />

        <RecommendationsModal
          isOpen={isRecommendationsOpen}
          onClose={() => setIsRecommendationsOpen(false)}
          data={currentMonthData}
          monthYear={currentMonthYear}
        />

        <DashboardHelpModal
          isOpen={isDashboardHelpOpen}
          onClose={() => setIsDashboardHelpOpen(false)}
          onOpenManageData={() => setIsImportExportModalOpen(true)}
          onOpenSupport={() => setIsSupportOpen(true)}
        />

        <ContactSupportModal
          isOpen={isSupportOpen}
          onClose={() => setIsSupportOpen(false)}
        />

        {/* Floating Help Button for Dashboard */}
        <button 
            onClick={() => setIsDashboardHelpOpen(true)}
            className="fixed bottom-8 right-8 w-14 h-14 bg-brand-primary text-white rounded-full shadow-2xl flex items-center justify-center hover:bg-brand-secondary transform hover:scale-110 transition-all z-40 group"
            aria-label="Dashboard Help Center"
        >
            <HelpCircleIcon />
            <span className="absolute right-full mr-4 px-3 py-1 bg-gray-900 text-white text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
                Help & Support
            </span>
        </button>

        <input
            type="file"
            accept=".json"
            ref={fileInputRef}
            onChange={handleFileImport}
            style={{ display: 'none' }}
        />
      </div>
    </div>
  );
};


function App() {
  const [view, setView] = useState<View>('dashboard');
  const path = window.location.pathname;

  // HANDLE SNAPSHOT VIEWING
  if (path.startsWith('/snapshot/')) {
    const snapshotId = path.substring('/snapshot/'.length);
    if (!snapshotId) {
        return (
            <div className="h-screen flex items-center justify-center bg-gray-100 dark:bg-gray-900">
                <p>Missing Snapshot ID</p>
            </div>
        );
    }
    return <SnapshotLoader snapshotId={snapshotId} />;
  }

  const { user, loading } = useAuth();

  // Allow users to see the privacy policy without being logged in
  if (view === 'privacy') {
    return <PrivacyPolicy onBack={() => setView('dashboard')} />;
  }

  if (loading) {
    return <LoadingScreen />;
  }

  if (!user) {
    return <AuthScreen onViewPrivacy={() => setView('privacy')} />;
  }

  return <MainApp view={view} setView={setView} />;
}

export default App;

import React, { useState } from 'react';
import ReactDOM from 'react-dom/client';
import html2canvas from 'html2canvas';
import { db } from '../firebase';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import type { MonthlyData } from '../types';
import { calculateNetWorth, formatCurrency, calculateMonthlyIncome, formatMonthYear } from '../utils/helpers';
import Button from './ui/Button';
import { CopyIcon, LinkIcon, EmailIcon, DownloadIcon, InfoIcon, CheckIcon, SmsIcon, NativeShareIcon } from './ui/Icons';
import Card from './ui/Card';
import Snapshot from './Snapshot';

interface ShareModalProps {
  isOpen: boolean;
  onClose: () => void;
  data?: MonthlyData;
  monthYear: string;
}

const ShareModal: React.FC<ShareModalProps> = ({ isOpen, onClose, data, monthYear }) => {
  const [copiedText, setCopiedText] = useState(false);
  const [copiedLink, setCopiedLink] = useState(false);
  const [shareableLink, setShareableLink] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);

  if (!isOpen || !data) return null;

  const netWorth = calculateNetWorth(data);
  const monthlyIncome = calculateMonthlyIncome(data.income.jobs);

  const summaryText = `
My WMCW Financial Snapshot (${formatMonthYear(monthYear)}):
- Net Worth: ${formatCurrency(netWorth)}
- Monthly Income: ${formatCurrency(monthlyIncome)}
- Total Assets: ${formatCurrency(data.assets.reduce((sum, a) => sum + a.value, 0))}
- Total Debt: ${formatCurrency(data.creditCards.reduce((s, c) => s + c.balance, 0) + data.loans.reduce((s, l) => s + l.balance, 0))}
  `.trim();

  const handleCopyText = () => {
    navigator.clipboard.writeText(summaryText);
    setCopiedText(true);
    setTimeout(() => setCopiedText(false), 2000);
  };

  const generateLink = async () => {
    if (!data || isGenerating) return;
    setIsGenerating(true);

    try {
      /**
       * SHORT URL LOGIC:
       * We store the snapshot in Firestore and use the Document ID as the link token.
       */
      const docRef = await addDoc(collection(db, 'shared_snapshots'), {
        monthYear,
        data,
        createdAt: serverTimestamp(),
        summary: {
            netWorth,
            monthlyIncome
        }
      });

      const link = `${window.location.origin}/snapshot/${docRef.id}`;
      setShareableLink(link);
    } catch (error: any) {
        console.error("CRITICAL: Error generating share link:", error);
        alert(`Failed to publish snapshot. Error: ${error.message || "Unknown connectivity issue"}`);
    } finally {
        setIsGenerating(false);
    }
  };

  const handleCopyLink = () => {
      if (!shareableLink) return;
      navigator.clipboard.writeText(shareableLink);
      setCopiedLink(true);
      setTimeout(() => setCopiedLink(false), 2000);
  }

  const handleNativeShare = async () => {
    if (!shareableLink) return;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `WMCW Snapshot - ${formatMonthYear(monthYear)}`,
          text: `Check out my financial snapshot for ${formatMonthYear(monthYear)}. Net Worth: ${formatCurrency(netWorth)}`,
          url: shareableLink,
        });
      } catch (err) {
        console.log('Share cancelled or failed', err);
      }
    } else {
      handleCopyLink();
    }
  };

  const handleEmailShare = () => {
    if (!shareableLink) return;

    const subject = encodeURIComponent(`Financial Snapshot for ${formatMonthYear(monthYear)}`);
    const body = encodeURIComponent(
      `Check out my WMCW Financial Snapshot for ${formatMonthYear(monthYear)}:\n\n` +
      `${summaryText}\n\n` +
      `View the full interactive report here:\n${shareableLink}`
    );

    window.location.href = `mailto:?subject=${subject}&body=${body}`;
  };

  const handleSmsShare = () => {
    if (!shareableLink) return;
    const smsBody = `Check out my WMCW Financial Snapshot for ${formatMonthYear(monthYear)}: ${shareableLink}`;
    window.location.href = `sms:?body=${encodeURIComponent(smsBody)}`;
  };

  const handleDownloadImage = async () => {
    if (!data) return;
    setIsGeneratingImage(true);

    const snapshotContainer = document.createElement('div');
    snapshotContainer.style.width = '1280px';
    snapshotContainer.style.position = 'absolute';
    snapshotContainer.style.left = '-9999px';
    document.body.appendChild(snapshotContainer);

    const root = ReactDOM.createRoot(snapshotContainer);
    const snapshotData = { monthYear, data };
    root.render(<Snapshot snapshotData={snapshotData} />);

    // Wait for rendering and styles
    await new Promise(resolve => setTimeout(resolve, 800));

    try {
        const canvas = await html2canvas(snapshotContainer, { 
            scale: 2,
            useCORS: true,
            backgroundColor: '#ffffff'
        });

        const imgData = canvas.toDataURL('image/jpeg', 0.95);
        const link = document.createElement('a');
        link.href = imgData;
        link.download = `financial-snapshot-${monthYear}.jpeg`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    } catch (error) {
        console.error("Error generating JPEG:", error);
        alert("Sorry, there was an error creating the image.");
    } finally {
        root.unmount();
        document.body.removeChild(snapshotContainer);
        setIsGeneratingImage(false);
    }
  };

  const canShareNative = !!navigator.share;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex justify-center items-center p-4">
      <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-2xl w-full max-w-xl overflow-hidden flex flex-col animate-fade-in border border-gray-100 dark:border-gray-800">
        <div className="p-6 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 dark:text-gray-100">Share & Publish Report</h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">Export your data for {formatMonthYear(monthYear)}</p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 transition-colors p-2 text-xl">✕</button>
        </div>

        <div className="p-6 space-y-8 max-h-[75vh] overflow-y-auto">
          {/* Publishing Section */}
           <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-bold flex items-center gap-2 text-purple-600 dark:text-purple-400">
                  <LinkIcon /> Publish Live Snapshot
                </h3>
                {shareableLink && (
                  <span className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 text-[10px] font-bold uppercase tracking-widest animate-pulse">
                    ● Live
                  </span>
                )}
              </div>

              <p className="text-sm text-gray-600 dark:text-gray-300">
                Publishing creates a unique, <span className="font-bold text-purple-600">Short URL</span> for your report. Send this link to anyone via text or email.
              </p>

              <div className="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-xl border border-blue-100 dark:border-blue-800/50 flex gap-3">
                <div className="text-blue-500 mt-0.5"><InfoIcon /></div>
                <div>
                   <p className="text-xs font-bold text-blue-700 dark:text-blue-300 uppercase tracking-tighter">Privacy Guarantee</p>
                   <p className="text-[11px] text-blue-600/80 dark:text-blue-400/80 mt-1 leading-relaxed">
                     Sharing <span className="font-bold">does NOT</span> expose passwords or account numbers. It only displays the summary data you see in the snapshot.
                   </p>
                </div>
              </div>

              {shareableLink ? (
                <div className="space-y-4 animate-fade-in">
                  <div className="relative">
                    <input 
                      type="text" 
                      readOnly 
                      value={shareableLink} 
                      className="w-full p-3 pr-12 border rounded-xl bg-gray-50 dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-sm font-mono text-brand-primary"
                      onFocus={(e) => e.target.select()}
                    />
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 text-positive">
                       <CheckIcon />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <Button onClick={handleCopyLink} className="bg-brand-primary hover:bg-brand-secondary text-white border-none flex-1">
                      <CopyIcon /> {copiedLink ? 'Link Copied!' : 'Copy Short URL'}
                    </Button>

                    {canShareNative ? (
                      <Button onClick={handleNativeShare} className="bg-brand-accent hover:bg-brand-secondary text-white border-none flex-1">
                        <NativeShareIcon /> Send to App
                      </Button>
                    ) : (
                      <Button onClick={handleSmsShare} className="bg-green-600 hover:bg-green-700 text-white border-none flex-1">
                        <SmsIcon /> Send via Text
                      </Button>
                    )}
                  </div>

                  <div className="flex flex-wrap gap-2">
                    <Button 
                      onClick={handleEmailShare}
                      className="flex-1 font-bold rounded-md transition-colors bg-gray-100 hover:bg-gray-200 text-gray-800 dark:bg-gray-800 dark:hover:bg-gray-700 dark:text-gray-100 border border-gray-200 dark:border-gray-700 py-2.5 px-6 text-sm"
                    >
                        <EmailIcon /> Email Snapshot
                    </Button>
                    {canShareNative && (
                      <Button onClick={handleSmsShare} className="bg-green-500 hover:bg-green-600 text-white border-none px-4" title="Send via SMS">
                        <SmsIcon />
                      </Button>
                    )}
                  </div>
                </div>
              ) : (
                <Button 
                    onClick={generateLink} 
                    disabled={isGenerating}
                    className="w-full py-4 bg-gradient-to-r from-purple-600 to-brand-primary hover:from-purple-700 hover:to-brand-secondary text-white border-none shadow-lg"
                >
                  {isGenerating ? (
                    <div className="flex items-center gap-2">
                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                        Publishing Snapshot...
                    </div>
                  ) : (
                    <><LinkIcon /> Generate & Publish Snapshot</>
                  )}
                </Button>
              )}
            </div>

          <div className="border-t border-gray-100 dark:border-gray-800 pt-6">
              <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                <CopyIcon /> Quick Summary
              </h3>
              <Card title="Dashboard Text" className="bg-gray-50 dark:bg-gray-800/50">
                <pre className="whitespace-pre-wrap p-4 text-xs font-mono text-gray-700 dark:text-gray-300 leading-relaxed">{summaryText}</pre>
              </Card>
              <div className="mt-4 flex justify-end">
                <Button onClick={handleCopyText} variant="secondary">
                    <CopyIcon />
                    {copiedText ? 'Summary Copied!' : 'Copy Text Summary'}
                </Button>
              </div>
          </div>

            <div className="border-t border-gray-100 dark:border-gray-800 pt-6">
                <h3 className="text-lg font-bold mb-2 flex items-center gap-2">
                  <DownloadIcon /> Export for Print
                </h3>
                <p className="text-sm text-gray-600 dark:text-gray-300 mb-4">
                    Download a high-resolution JPEG of the dashboard. Perfect for attachments or printing.
                </p>
                <Button onClick={handleDownloadImage} disabled={isGeneratingImage} variant="secondary" className="w-full py-3">
                    {isGeneratingImage ? (
                      <span className="flex items-center gap-2">
                        <div className="w-4 h-4 border-2 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
                        Generating Image...
                      </span>
                    ) : (
                      <><DownloadIcon /> Download JPEG Image</>
                    )}
                </Button>
            </div>

        </div>
        <div className="p-6 flex justify-end gap-3 bg-gray-50 dark:bg-gray-900 border-t border-gray-100 dark:border-gray-800">
          <Button onClick={onClose} variant="secondary">Dismiss</Button>
        </div>
      </div>
    </div>
  );
};

export default ShareModal;

import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';
import process from 'node:process';

// https://vitejs.dev/config/
export default defineConfig(({ mode }) => {
  // Load env file based on `mode` in the current working directory.
  // Set the third parameter to '' to load all env vars regardless of the `VITE_` prefix.
  const env = loadEnv(mode, process.cwd(), '');

  return {
    plugins: [react()],
    define: {
      // Injects keys into the client-side code.
      // This allows code to use `process.env.VARIABLE_NAME` directly.
      'process.env.API_KEY': JSON.stringify(env.API_KEY),
      'process.env.FIREBASE_API_KEY': JSON.stringify(env.FIREBASE_API_KEY),
      'process.env.FIREBASE_AUTH_DOMAIN': JSON.stringify(env.FIREBASE_AUTH_DOMAIN),
